 1	import * as React from 'react';
 2	import { Tooltip } from '@patternfly/react-core';
 3	import {
 4	  DEFAULT_DECORATOR_RADIUS,
 5	  Decorator,
 6	  Node,
 7	  TopologyQuadrant,
 8	  getDefaultShapeDecoratorCenter,
 9	  observer
10	} from '@patternfly/react-topology';
11	import { IconType } from 'config/Icons';
12	import { kialiStyle } from 'styles/StyleUtils';
13	import { PFColors } from 'components/Pf/PfColors';
14	
15	interface Props {
16	  element: Node;
17	  icon: IconType;
18	  quadrant: TopologyQuadrant;
19	  tooltip?: string;
20	}
21	
22	const decoratorStyle = kialiStyle({
23	  color: PFColors.White,
24	  $nest: {
25	    '& .pf-topology__node__decorator__bg': {
26	      fill: PFColors.Purple500
27	    },
28	    '& .pf-topology__node__decorator__icon': {
29	      color: PFColors.White,
30	      $nest: {
31	        '& svg': {
32	          fill: PFColors.White
33	        }
34	      }
35	    }
36	  }
37	});
38	
39	const NodeDecoratorInner: React.FC<Props> = ({ element, quadrant, icon, tooltip }) => {
40	  const { x, y } = getDefaultShapeDecoratorCenter(quadrant, element);
41	  const decoratorRef = React.useRef<SVGAElement | null>(null);
42	
43	  return (
44	    <Tooltip triggerRef={decoratorRef} content={tooltip ?? icon.text}>
45	      <Decorator
46	        className={decoratorStyle}
47	        innerRef={decoratorRef}
48	        x={x}
49	        y={y}
50	        radius={DEFAULT_DECORATOR_RADIUS * 0.9}
51	        showBackground
52	        icon={React.createElement(icon.icon)}
53	      />
54	    </Tooltip>
55	  );
56	};
57	
58	export const NodeDecorator = observer(NodeDecoratorInner);

